{
    "level": "A1–A2",
    "intro": "W tej sekcji przećwiczysz <strong>am / is / are</strong>, formy <strong>was / were</strong>, model <strong>will be</strong>, przeczenia, pytania oraz <strong>there is / there are</strong>.",
    "rules": [
        {
            "label": "Formy czasu teraźniejszego",
            "color": "emerald",
            "text": "Zacznij od <strong>am / is / are</strong> w prostych zdaniach.",
            "example": "I am late. / She is ready. / They are here."
        },
        {
            "label": "Przeszłość i przyszłość",
            "color": "blue",
            "text": "Potem dodaj <strong>was / were</strong> oraz model <strong>will be</strong>.",
            "example": "I was tired yesterday. / They will be here soon."
        },
        {
            "label": "Pytania i there",
            "color": "amber",
            "text": "Następnie przećwicz pytania bez <strong>do / does / did</strong> i konstrukcje z <strong>there</strong>.",
            "example": "Were they ready? / Will she be late? / There is a book on the table."
        }
    ]
}

{
    "title": "1. Zestaw startowy",
    "intro": "Ta ścieżka prowadzi od najprostszych form do przeszłości, przyszłości i konstrukcji z there.",
    "items": [
        {
            "label": "A1",
            "title": "Formy czasu teraźniejszego",
            "subtitle": "am / is / are w krótkich zdaniach twierdzących."
        },
        {
            "label": "A1",
            "title": "Przeczenia",
            "subtitle": "am not, is not, are not i najczęstsze skróty."
        },
        {
            "label": "A1",
            "title": "Pytania i krótkie odpowiedzi",
            "subtitle": "Am I...?, Is he...?, Are they...? i krótkie odpowiedzi."
        },
        {
            "label": "A1–A2",
            "title": "Formy czasu przeszłego",
            "subtitle": "was / were, przeczenia i pytania w przeszłości."
        },
        {
            "label": "A1–A2",
            "title": "Czas przyszły",
            "subtitle": "will be, won't be i proste pytania o przyszłość."
        },
        {
            "label": "A1–A2",
            "title": "Konstrukcje there is / there are",
            "subtitle": "Jak opisywać, co jest albo czego nie ma w danym miejscu."
        }
    ]
}

{
    "title": "2. Co przećwiczysz",
    "sections": [
        {
            "label": "am / is / are",
            "color": "emerald",
            "description": "Zobaczysz, która forma łączy się z <strong>I</strong>, <strong>he / she / it</strong> oraz <strong>you / we / they</strong>.",
            "examples": [
                {
                    "en": "I am tired. / She is a student. / They are at work.",
                    "ua": "Podstawowe modele do mówienia o stanie, roli i miejscu."
                }
            ]
        },
        {
            "label": "was / were / will be",
            "color": "blue",
            "description": "Dodasz przeszłe i przyszłe formy <strong>to be</strong>, żeby mówić o tym, co było wcześniej i co będzie później.",
            "examples": [
                {
                    "en": "He was at home yesterday. / They will be ready soon.",
                    "ua": "Formy przeszłe i przyszłe czasownika to be."
                }
            ]
        },
        {
            "label": "Pytania i there",
            "color": "amber",
            "description": "Nauczysz się budować pytania i krótkie odpowiedzi, a osobno opisywać obecność czegoś w danym miejscu.",
            "examples": [
                {
                    "en": "Was she tired? / Will they be here? / There are two chairs in the kitchen.",
                    "ua": "Pytania, krótkie odpowiedzi i model do opisu istnienia czegoś w miejscu."
                }
            ]
        }
    ]
}
